import React, { useState } from 'react';
import * as Tabs from '@radix-ui/react-tabs';

const ControlledTabs = () => {
  const [activeTab, setActiveTab] = useState("profile");

  return (
    <Tabs.Root value={activeTab} onValueChange={setActiveTab} className="w-[400px]">
      <Tabs.List className="flex border-b">
        <Tabs.Trigger value="profile" className="px-4 py-2 hover:bg-gray-100 data-[state=active]:border-b-2 data-[state=active]:border-blue-500">
          Profile
        </Tabs.Trigger>
        <Tabs.Trigger value="settings" className="px-4 py-2 hover:bg-gray-100 data-[state=active]:border-b-2 data-[state=active]:border-blue-500">
          Settings
        </Tabs.Trigger>
      </Tabs.List>
      <Tabs.Content value="profile" className="p-4">
        <p>This is your profile information.</p>
        <button onClick={() => setActiveTab("settings")} className="mt-2 p-2 bg-blue-500 text-white rounded">Go to Settings</button>
      </Tabs.Content>
      <Tabs.Content value="settings" className="p-4">
        <p>Adjust your settings here.</p>
        <button onClick={() => setActiveTab("profile")} className="mt-2 p-2 bg-green-500 text-white rounded">Go to Profile</button>
      </Tabs.Content>
    </Tabs.Root>
  );
};

export default ControlledTabs;
